// React: JSX is JavaScript — conditions and loops are plain JS
function UserList({ users, isLoading }) {
  if (isLoading) return <p>Loading...</p>;
  return (
    <ul>
      {users.map(u => (
        <li key={u.id}>{u.name}</li>
      ))}
    </ul>
  );
}

// Angular: decorator-based components, HTML templates with directives
@Component({
  selector: 'app-user-list',
  template: `
    <p *ngIf="isLoading">Loading...</p>
    <ul>
      <li *ngFor="let u of users" [class.active]="u.selected">
        {{ u.name }}
      </li>
    </ul>
  `
})
export class UserListComponent {
  @Input() users: User[] = [];
  @Input() isLoading = false;
}

// The same counter in all four — different syntax, same idea

// React
const [count, setCount] = useState(0)
<button onClick={() => setCount(c => c + 1)}>{count}</button>

// Angular (Signals)
count = signal(0)
<button (click)="count.set(count() + 1)">{{ count() }}</button>

// Vue 3
const count = ref(0)
<button @click="count.value++">{{ count }}</button>

// Svelte 5
let count = $state(0)
<button onclick={() => count++}>{count}</button>

// React — the baseline
function UserCard({ userId }) {
  const [user, setUser] = useState(null);
  const [status, setStatus] = useState('idle');

  useEffect(() => {
    setStatus('loading');
    fetchUser(userId)
      .then(u => { setUser(u); setStatus('success'); })
      .catch(() => setStatus('error'));
  }, [userId]);

  if (status === 'loading') return <Spinner />;
  if (status === 'error')   return <p>Failed to load.</p>;
  if (!user)                return null;
  return <h2>{user.name}</h2>;
}

// Drop a React component into any HTML page
import { createRoot } from 'react-dom/client';
import SearchWidget from './SearchWidget';

// Angular / Vue / plain HTML host just provides this div
const container = document.getElementById('search-mount');
if (container) {
  createRoot(container).render(<SearchWidget />);
}

// React Testing Library — test what the user sees
import { render, screen, fireEvent } from '@testing-library/react';
import LikeButton from './LikeButton';

test('toggles liked state on click', () => {
  render(<LikeButton />);
  const btn = screen.getByRole('button', { name: /like/i });
  fireEvent.click(btn);
  expect(btn).toHaveTextContent(/unlike/i);
});

// React + TypeScript: typed props
interface ButtonProps {
  label: string;
  onClick: () => void;
  disabled?: boolean;  // optional
}

function Button({ label, onClick, disabled = false }: ButtonProps) {
  return (
    <button onClick={onClick} disabled={disabled}>
      {label}
    </button>
  );
}
